import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"六经辨证跨医家索引","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/01-伤寒六经辨证.md","filePath":"tcm-data/06-跨病证索引/01-伤寒六经辨证.md","lastUpdated":1781084559000}'),n={name:"tcm-data/06-跨病证索引/01-伤寒六经辨证.md"};function r(s,t,i,g,o,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="六经辨证跨医家索引" tabindex="-1">六经辨证跨医家索引 <a class="header-anchor" href="#六经辨证跨医家索引" aria-label="Permalink to &quot;六经辨证跨医家索引&quot;">​</a></h1><blockquote><p>六经病证在不同医家手中的不同认识和处理</p></blockquote><hr><h2 id="太阳病" tabindex="-1">太阳病 <a class="header-anchor" href="#太阳病" aria-label="Permalink to &quot;太阳病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">风寒束表，荣卫不和</td><td style="text-align:left;">桂枝汤、麻黄汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">膀胱寒水，经气不利</td><td style="text-align:left;">桂枝汤加苓泽</td></tr><tr><td style="text-align:left;"><strong>彭子益</strong></td><td style="text-align:left;">木气疏泄被寒邪约束</td><td style="text-align:left;">桂枝汤升肝木</td></tr></tbody></table><h3 id="太阳病延伸" tabindex="-1">太阳病延伸 <a class="header-anchor" href="#太阳病延伸" aria-label="Permalink to &quot;太阳病延伸&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">病证</th><th style="text-align:left;">伤寒论方</th><th style="text-align:left;">黄元御方</th></tr></thead><tbody><tr><td style="text-align:left;">项背强</td><td style="text-align:left;">桂枝加葛根汤</td><td style="text-align:left;">桂枝加葛根汤</td></tr><tr><td style="text-align:left;">气喘</td><td style="text-align:left;">桂枝加厚朴杏子汤/麻黄汤</td><td style="text-align:left;">桂枝加半夏</td></tr><tr><td style="text-align:left;">蓄水</td><td style="text-align:left;">五苓散</td><td style="text-align:left;">五苓散去桂加泽泻</td></tr></tbody></table><hr><h2 id="阳明病" tabindex="-1">阳明病 <a class="header-anchor" href="#阳明病" aria-label="Permalink to &quot;阳明病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">胃家实，燥热内结</td><td style="text-align:left;">白虎汤、承气汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">阳明燥金，土燥生热</td><td style="text-align:left;">地魄汤法</td></tr></tbody></table><hr><h2 id="少阳病" tabindex="-1">少阳病 <a class="header-anchor" href="#少阳病" aria-label="Permalink to &quot;少阳病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">半表半里，枢机不利</td><td style="text-align:left;">小柴胡汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">相火不降，胆经郁热</td><td style="text-align:left;">金鼎汤/小柴胡去参加龙牡</td></tr><tr><td style="text-align:left;"><strong>彭子益</strong></td><td style="text-align:left;">胆经相火不降入肾</td><td style="text-align:left;">小柴胡汤降胆火</td></tr></tbody></table><hr><h2 id="太阴病" tabindex="-1">太阴病 <a class="header-anchor" href="#太阴病" aria-label="Permalink to &quot;太阴病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">脾虚寒湿</td><td style="text-align:left;">理中丸、四逆汤类</td></tr><tr><td style="text-align:left;"><strong>李东垣</strong></td><td style="text-align:left;">脾胃气虚，清阳不升</td><td style="text-align:left;">补中益气汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">己土湿陷，中轴不转</td><td style="text-align:left;"><strong>黄芽汤</strong>（普光基础方）</td></tr></tbody></table><hr><h2 id="少阴病" tabindex="-1">少阴病 <a class="header-anchor" href="#少阴病" aria-label="Permalink to &quot;少阴病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">心肾虚衰，寒化或热化</td><td style="text-align:left;">四逆汤/黄连阿胶汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">水寒不升，君火不明</td><td style="text-align:left;"><strong>天魂汤</strong>（附子+干姜）</td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">阳虚至极，一线生机</td><td style="text-align:left;">破格救心汤</td></tr></tbody></table><h3 id="少阴病是普光的核心病机" tabindex="-1">少阴病是普光的核心病机 <a class="header-anchor" href="#少阴病是普光的核心病机" aria-label="Permalink to &quot;少阴病是普光的核心病机&quot;">​</a></h3><p>普光腰凉+无力+脉象(推测沉微) → <strong>少阴寒化证</strong>，正合四逆汤/天魂汤法。</p><hr><h2 id="厥阴病" tabindex="-1">厥阴病 <a class="header-anchor" href="#厥阴病" aria-label="Permalink to &quot;厥阴病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">寒热错杂，厥热胜复</td><td style="text-align:left;">乌梅丸</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">风木不达，郁而化火</td><td style="text-align:left;">桂枝+白芍+龙牡</td></tr><tr><td style="text-align:left;"><strong>彭子益</strong></td><td style="text-align:left;">木气郁极，疏泄失常</td><td style="text-align:left;">乌梅白糖汤</td></tr></tbody></table><hr><p><em>本索引可在后续扩展到&quot;六经辨证与现代病对照&quot;等内容。</em></p>',26)])])}const y=e(n,[["render",r]]);export{f as __pageData,y as default};
